1	import { betterAuth } from "better-auth";
2	import { prismaAdapter } from "better-auth/adapters/prisma";
3	import { admin } from "better-auth/plugins";
4	// If your Prisma file is located elsewhere, you can change the path
5	import { prisma } from "./prisma";
6	
7	// const prisma = new PrismaClient();
8	
9	export const auth = betterAuth({
10	  database: prismaAdapter(prisma, {
11	    provider: "postgresql",
12	  }),
13	  emailAndPassword: {
14	    enabled: true,
15	    requireEmailVerification: true,
16	    autoSignIn: false,
17	    
18	    // try to singin with your email
19	    /*onExistingUserSignUp: async ({ user }, request) => {
20	      
21	    },*/
22	    
23	    // Reset password via Plunk
24	    sendResetPassword: async ({ user, url }) => {
25	      await $fetch("https://api.useplunk.com/v1/send", {
26	        method: "POST",
27	        headers: {
28	          "Content-Type": "application/json",
29	          Authorization: `Bearer ${process.env.PLUNK_SECRET_API_KEY}`,
30	        },
31	        body: {
32	          to: user.email,
33	          subject: "Réinitialisation de ton mot de passe",
34	          subscribed: true,
35	          name: "DNG Blog",
36	          body: `
37	             <h2>Réinitialisation du mot de passe</h2>
38	             <p>Clique sur le lien ci-dessous pour réinitialiser ton mot de passe :</p>
39	             <a href="${url}" style="
40	               display: inline-block;
41	               padding: 12px 24px;
42	               background: #4f46e5;
43	               color: white;
44	               border-radius: 6px;
45	               text-decoration: none;
46	             ">Réinitialiser mon mot de passe</a>
47	             <p>Ce lien expire dans 1h. Si tu n'as pas demandé cette action, ignore cet email.</p>
48	           `,
49	          data: {},
50	        },
51	      })
52	    }
53	  },
54	  emailVerification: {
55	    sendOnSignUp: true, // envoie automatiquement l'email à l'inscription
56	    autoSignInAfterVerification: true, // connecte l'utilisateur après vérification
57	    sendVerificationEmail: async ({ user, url }) => {
58	      await $fetch("https://api.useplunk.com/v1/send", {
59	        method: "POST",
60	        headers: {
61	          "Content-Type": "application/json",
62	          Authorization: `Bearer ${process.env.PLUNK_SECRET_API_KEY}`,
63	        },
64	        body: {
65	          to: user.email,
66	          subject: "Vérifie ton adresse email",
67	          subscribed: true,
68	          name: "DNG Blog",
69	          body: `
70	              <h2>Bienvenue ${user.name} !</h2>
71	              <p>Clique sur le lien ci-dessous pour vérifier ton adresse email :</p>
72	              <a href="${url}" style="
73	                display: inline-block;
74	                padding: 12px 24px;
75	                background: #4f46e5;
76	                color: white;
77	                border-radius: 6px;
78	                text-decoration: none;
79	              ">Vérifier mon email</a>
80	              <p>Ce lien expire dans 24h.</p>
81	            `,
82	          data: {},
83	        },
84	      });
85	    },
86	  },
87	  plugins: [
88	    admin({
89	      defaultRole: 'reader', // tout nouvel utilisateur sera "reader" par défaut
90	      adminRoles: ['admin'],  // les rôles considérés comme "admin" par le plugin
91	    }),
92	  ],
93	  socialProviders: {
94	    github: {
95	      clientId: process.env.GITHUB_CLIENT_ID as string,
96	      clientSecret: process.env.GITHUB_CLIENT_SECRET as string,
97	    },
98	  },
99	  session: {
100	    cookieCache: {
101	      enabled: true,
102	      maxAge: 5 * 60, // Cache duration in seconds (5 minutes)
103	      strategy: "compact", // or "jwt" or "jwe"
104	    },
105	    expiresIn: 60 * 60 * 24 * 7, // 7 days
106	    updateAge: 60 * 60 * 24, // 1 day (every 1 day the session expiration is updated)
107	  },
108	});
